export const CONNECTOR_SOURCES = 590;
export const CONNECTOR_DESTINATIONS = 56;

export const CONNECTOR_CATEGORY_COUNTS: Record<string, number> = {"api":562,"database":53,"file":22,"vectorstore":8,"message_queue":1};

export const CONNECTOR_STATUS_COUNTS: Record<string, number> = {"planned_native_port":644,"enabled":2};

const BY_SLUG: Record<string, ConnectorMeta> = Object.fromEntries(
  CONNECTOR_CATALOG.map((c) => [c.slug, c]),
);

export function connectorBySlug(slug: string): ConnectorMeta | undefined {
  return BY_SLUG[slug];
}
